def get_tenant_modules(tenant_doc: Dict[str, Any]) -> Dict[str, bool]:
    """Merge stored tenant modules with tier-based defaults.

    Uses the subscription tier to determine default modules.
    If tenant has explicit modules stored, those override the defaults.
    """
    from subscription_models import get_plan_default_modules

    # Get the tier
    tier = (tenant_doc.get("subscription_tier") or "basic").lower()
    if tier == "pro":
        tier = "professional"
    if tier == "ultra":
        tier = "enterprise"

    # Start with tier-based defaults (not all-True)
    merged = get_plan_default_modules(tier)

    # Override with explicitly stored modules (if any)
    modules = tenant_doc.get("modules")
    if isinstance(modules, dict) and len(modules) > 0:
        for key, value in modules.items():
            try:
                merged[key] = bool(value)
            except Exception:
                continue

    return merged


def require_module(module_name: str):
    """Dependency to ensure the current hotel has a specific module enabled."""

    async def dependency(current_user: User = Depends(get_current_user)) -> None:
        if not current_user.tenant_id:
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail="Bu işlem için bir otel hesabı gerekir",
            )

        # Find tenant by logical id or Mongo _id
        tenant_doc = await db.tenants.find_one({"id": current_user.tenant_id})
        if not tenant_doc:
            try:
                from bson import ObjectId

                tenant_doc = await db.tenants.find_one(
                    {"_id": ObjectId(current_user.tenant_id)}
                )
            except Exception:
                tenant_doc = None

        if not tenant_doc:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail="Otel bulunamadı",
            )

        modules = get_tenant_modules(tenant_doc)

        # Eğer detaylı bir AI alt modu isteniyorsa ve ana 'ai' kapalıysa direkt engelle
        if module_name.startswith("ai_"):
            if not modules.get("ai", False):
                raise HTTPException(
                    status_code=status.HTTP_403_FORBIDDEN,
                    detail="AI modülleri bu otel için aktif değil",
                )

        if not modules.get(module_name, False):
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail=f"{module_name} modülü bu otel için aktif değil",
            )

    return dependency


async def require_admin(current_user: User = Depends(get_current_user)) -> User:
    """Allow only admin users (otel yöneticileri) to access admin endpoints."""
    if current_user.role != UserRole.ADMIN and current_user.role != UserRole.SUPER_ADMIN:
        raise HTTPException(
            status_code=status.HTTP_403_FORBIDDEN,
            detail="Bu işlemi sadece yönetici kullanıcılar yapabilir",
        )
    return current_user


# ============= ONLINE CHECK-IN & PRE-ARRIVAL ENDPOINTS =============

@api_router.post("/checkin/online")
async def submit_online_checkin(
    checkin_data: dict,
    current_user: User = Depends(get_current_user)
):
    """Online check-in submission"""
    from online_checkin_models import OnlineCheckinRequest, OnlineCheckinResponse, UpsellOffer
    
    # Import here to avoid circular dependency
    request = OnlineCheckinRequest(**checkin_data)
    
    # Verify booking belongs to user
    booking = await db.bookings.find_one({
        'id': request.booking_id,
        'tenant_id': current_user.tenant_id
    }, {'_id': 0})
    
    if not booking:
        raise HTTPException(status_code=404, detail="Rezervasyon bulunamadı")
    
    # Create online check-in record
    checkin_record = {
        'id': str(uuid.uuid4()),
        'booking_id': request.booking_id,
        'tenant_id': current_user.tenant_id,
        'guest_id': booking['guest_id'],
        
        # Guest info
        'passport_number': request.passport_number,
        'passport_expiry': request.passport_expiry,
        'nationality': request.nationality,
        
        # Arrival details
        'estimated_arrival_time': request.estimated_arrival_time,
        'flight_number': request.flight_number,
        'coming_from': request.coming_from,
        
        # Room preferences
        'room_view': request.room_view,
        'floor_preference': request.floor_preference,
        'bed_type': request.bed_type,
        'pillow_type': request.pillow_type,
        'room_temperature': request.room_temperature,
        
        # Special requests
        'special_requests': request.special_requests,
        'dietary_restrictions': request.dietary_restrictions,
        'accessibility_needs': request.accessibility_needs,
        
        # Additional
        'newspaper_preference': request.newspaper_preference,
        'smoking_preference': request.smoking_preference,
        'connecting_rooms': request.connecting_rooms,
        'quiet_room': request.quiet_room,
        
        # Communication
        'mobile_number': request.mobile_number,
        'whatsapp_number': request.whatsapp_number,
        
        # Status
        'status': 'pending',
        'submitted_at': datetime.now(timezone.utc).isoformat(),
        'processed': False
    }
    
    await db.online_checkins.insert_one(checkin_record)
    
    # Update booking with preferences
    await db.bookings.update_one(
        {'id': request.booking_id},
        {
            '$set': {
                'online_checkin_completed': True,
                'online_checkin_at': datetime.now(timezone.utc).isoformat(),
                'special_requests': request.special_requests,
                'estimated_arrival_time': request.estimated_arrival_time
            }
        }
    )
    
    # Generate upsell offers
    upsell_offers = []
    
    # Room upgrade offer
    current_room = await db.rooms.find_one({'id': booking['room_id']}, {'_id': 0})
    if current_room and current_room['room_type'] == 'Standard':
        upgrade_offer = {
            'id': str(uuid.uuid4()),
            'type': 'room_upgrade',
            'title': 'Deluxe Oda Upgrade',
            'description': 'Konaklama deneyiminizi Deluxe odamıza yükseltin! Daha geniş alan, daha iyi manzara.',
            'original_price': 100.0,
            'discounted_price': 75.0,
            'savings': 25.0
        }
        upsell_offers.append(upgrade_offer)
    
    # Early check-in offer
    if request.estimated_arrival_time:
        try:
            arrival_hour = int(request.estimated_arrival_time.split(':')[0])
            if arrival_hour < 14:  # Before standard check-in
                early_checkin_offer = {
                    'id': str(uuid.uuid4()),
                    'type': 'early_checkin',
                    'title': 'Erken Check-in Garantisi',
                    'description': f'Odanız {request.estimated_arrival_time} saatinde hazır olacak. Ekstra ücret ödemeden erken giriş yapın!',
                    'original_price': 50.0,
                    'discounted_price': 35.0,
                    'savings': 15.0
                }
                upsell_offers.append(early_checkin_offer)
        except:
            pass
    
    # Save upsell offers
    for offer in upsell_offers:
        offer_doc = {
            **offer,
            'booking_id': request.booking_id,
            'tenant_id': current_user.tenant_id,
            'guest_id': booking['guest_id'],
            'status': 'pending',
            'offered_at': datetime.now(timezone.utc).isoformat()
        }
        await db.upsell_offers.insert_one(offer_doc)
    
    return {
        'checkin_id': checkin_record['id'],
        'booking_id': request.booking_id,
        'status': 'approved',
        'room_number': current_room.get('room_number') if current_room else None,
        'estimated_ready_time': '14:00',
        'upsell_offers': upsell_offers,
        'check_in_instructions': 'Lütfen resepsiyona geldiğinizde kimliğinizi ibraz edin. Odanız hazır olacaktır.',
        'message': 'Online check-in başarıyla tamamlandı!'
    }

