    await db.external_reviews.update_one(
        {'id': review_id},
        {
            '$set': {
                'response': response_text,
                'responded_at': datetime.now(timezone.utc).isoformat(),
                'responded_by': current_user.id,
                'status': 'responded'
            }
        }
    )
    
    return {'message': 'Response posted successfully'}


